INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (898, 'Introducing Whisper', 'We’ve trained and are open-sourcing a neural net called Whisper that approaches human level robustness and accuracy on English speech recognition.', 'We’ve trained and are open-sourcing a neural net called Whisper that approaches human level robustness and accuracy on English speech recognition.', 14, 'OpenAI Blog', 'https://openai.com/index/whisper', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2022-09-21 07:00:00.000000', '2026-03-16 06:51:03.540802', 'https://openai.com/index/whisper', 0.0, 0);
