INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (904, 'DALL·E now available in beta', 'We’ll invite 1 million people from our waitlist over the coming weeks. Users can create with DALL·E using free credits that refill every month, and buy additional credits in 115-generation increments for $15.', 'We’ll invite 1 million people from our waitlist over the coming weeks. Users can create with DALL·E using free credits that refill every month, and buy additional credits in 115-generation increments for $15.', 14, 'OpenAI Blog', 'https://openai.com/index/dall-e-now-available-in-beta', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Product"]', '2022-07-20 07:00:00.000000', '2026-03-16 06:51:03.540860', 'https://openai.com/index/dall-e-now-available-in-beta', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (905, 'Reducing bias and improving safety in DALL·E 2', 'Today, we are implementing a new technique so that DALL·E generates images of people that more accurately reflect the diversity of the world’s population.', 'Today, we are implementing a new technique so that DALL·E generates images of people that more accurately reflect the diversity of the world’s population.', 14, 'OpenAI Blog', 'https://openai.com/index/reducing-bias-and-improving-safety-in-dall-e-2', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Product"]', '2022-07-18 07:00:00.000000', '2026-03-16 06:51:03.540869', 'https://openai.com/index/reducing-bias-and-improving-safety-in-dall-e-2', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (906, 'DALL·E 2: Extending creativity', 'As part of our DALL·E 2 research preview, more than 3,000 artists from more than 118 countries have incorporated DALL·E into their creative workflows. The artists in our early access group have helped us discover new uses for DALL·E and have served as key voices as we’ve made decisions about DALL·E’s features.', 'As part of our DALL·E 2 research preview, more than 3,000 artists from more than 118 countries have incorporated DALL·E into their creative workflows. The artists in our early access group have helped us discover new uses for DALL·E and have served as key voices as we’ve made decisions about DALL·E’s features.', 14, 'OpenAI Blog', 'https://openai.com/index/dall-e-2-extending-creativity', '', 'ai_tech', '["Company", "GPT", "AI", "OpenAI"]', '2022-07-14 07:00:00.000000', '2026-03-16 06:51:03.540879', 'https://openai.com/index/dall-e-2-extending-creativity', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (907, 'DALL·E 2 pre-training mitigations', 'In order to share the magic of DALL·E 2 with a broad audience, we needed to reduce the risks associated with powerful image generation models. To this end, we put various guardrails in place to prevent generated images from violating our content policy.', 'In order to share the magic of DALL·E 2 with a broad audience, we needed to reduce the risks associated with powerful image generation models. To this end, we put various guardrails in place to prevent generated images from violating our content policy.', 14, 'OpenAI Blog', 'https://openai.com/index/dall-e-2-pre-training-mitigations', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2022-06-28 07:00:00.000000', '2026-03-16 06:51:03.540889', 'https://openai.com/index/dall-e-2-pre-training-mitigations', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (908, 'Learning to play Minecraft with Video PreTraining', 'We trained a neural network to play Minecraft by Video PreTraining (VPT) on a massive unlabeled video dataset of human Minecraft play, while using only a small amount of labeled contractor data. With fine-tuning, our model can learn to craft diamond tools, a task that usually takes proficient humans over 20 minutes (24,000 actions). Our model uses the native human interface of keypresses and mouse movements, making it quite general, and represents a step towards general computer-using agents.', 'We trained a neural network to play Minecraft by Video PreTraining (VPT) on a massive unlabeled video dataset of human Minecraft play, while using only a small amount of labeled contractor data. With fine-tuning, our model can learn to craft diamond tools, a task that usually takes proficient humans over 20 minutes (24,000 actions). Our model uses the native human interface of keypresses and mouse movements, making it quite general, and represents a step towards general computer-using agents.', 14, 'OpenAI Blog', 'https://openai.com/index/vpt', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2022-06-23 07:00:00.000000', '2026-03-16 06:51:03.540899', 'https://openai.com/index/vpt', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (909, 'Evolution through large models', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/evolution-through-large-models', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2022-06-17 07:00:00.000000', '2026-03-16 06:51:03.540908', 'https://openai.com/index/evolution-through-large-models', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (910, 'AI-written critiques help humans notice flaws', 'We trained “critique-writing” models to describe flaws in summaries. Human evaluators find flaws in summaries much more often when shown our model’s critiques. Larger models are better at self-critiquing, with scale improving critique-writing more than summary-writing. This shows promise for using AI systems to assist human supervision of AI systems on difficult tasks.', 'We trained “critique-writing” models to describe flaws in summaries. Human evaluators find flaws in summaries much more often when shown our model’s critiques. Larger models are better at self-critiquing, with scale improving critique-writing more than summary-writing. This shows promise for using AI systems to assist human supervision of AI systems on difficult tasks.', 14, 'OpenAI Blog', 'https://openai.com/index/critiques', '', 'ai_tech', '["GPT", "Safety & Alignment", "AI", "OpenAI"]', '2022-06-13 07:00:00.000000', '2026-03-16 06:51:03.540918', 'https://openai.com/index/critiques', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (911, 'Techniques for training large neural networks', 'Large neural networks are at the core of many recent advances in AI, but training them is a difficult engineering and research challenge which requires orchestrating a cluster of GPUs to perform a single synchronized calculation.', 'Large neural networks are at the core of many recent advances in AI, but training them is a difficult engineering and research challenge which requires orchestrating a cluster of GPUs to perform a single synchronized calculation.', 14, 'OpenAI Blog', 'https://openai.com/index/techniques-for-training-large-neural-networks', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2022-06-09 07:00:00.000000', '2026-03-16 06:51:03.540927', 'https://openai.com/index/techniques-for-training-large-neural-networks', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (912, 'Best practices for deploying language models', 'Cohere, OpenAI, and AI21 Labs have developed a preliminary set of best practices applicable to any organization developing or deploying large language models.', 'Cohere, OpenAI, and AI21 Labs have developed a preliminary set of best practices applicable to any organization developing or deploying large language models.', 14, 'OpenAI Blog', 'https://openai.com/index/best-practices-for-deploying-language-models', '', 'ai_tech', '["GPT", "Safety & Alignment", "AI", "OpenAI"]', '2022-06-02 07:00:00.000000', '2026-03-16 06:51:03.540937', 'https://openai.com/index/best-practices-for-deploying-language-models', 0.0, 0);
