INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (922, 'Lessons learned on language model safety and misuse', 'We describe our latest thinking in the hope of helping other AI developers address safety and misuse of deployed models.', 'We describe our latest thinking in the hope of helping other AI developers address safety and misuse of deployed models.', 14, 'OpenAI Blog', 'https://openai.com/index/language-model-safety-and-misuse', '', 'ai_tech', '["GPT", "Safety & Alignment", "AI", "OpenAI"]', '2022-03-03 08:00:00.000000', '2026-03-16 06:51:03.541114', 'https://openai.com/index/language-model-safety-and-misuse', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (923, 'Solving (some) formal math olympiad problems', 'We built a neural theorem prover for Lean that learned to solve a variety of challenging high-school olympiad problems, including problems from the AMC12 and AIME competitions, as well as two problems adapted from the IMO.', 'We built a neural theorem prover for Lean that learned to solve a variety of challenging high-school olympiad problems, including problems from the AMC12 and AIME competitions, as well as two problems adapted from the IMO.', 14, 'OpenAI Blog', 'https://openai.com/index/formal-math', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2022-02-02 08:00:00.000000', '2026-03-16 06:51:03.541124', 'https://openai.com/index/formal-math', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (924, 'Aligning language models to follow instructions', 'We’ve trained language models that are much better at following user intentions than GPT-3 while also making them more truthful and less toxic, using techniques developed through our alignment research. These InstructGPT models, which are trained with humans in the loop, are now deployed as the default language models on our API.', 'We’ve trained language models that are much better at following user intentions than GPT-3 while also making them more truthful and less toxic, using techniques developed through our alignment research. These InstructGPT models, which are trained with humans in the loop, are now deployed as the default language models on our API.', 14, 'OpenAI Blog', 'https://openai.com/index/instruction-following', '', 'ai_tech', '["GPT", "Safety & Alignment", "AI", "OpenAI"]', '2022-01-27 08:00:00.000000', '2026-03-16 06:51:03.541134', 'https://openai.com/index/instruction-following', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (925, 'Introducing text and code embeddings', 'We are introducing embeddings, a new endpoint in the OpenAI API that makes it easy to perform natural language and code tasks like semantic search, clustering, topic modeling, and classification.', 'We are introducing embeddings, a new endpoint in the OpenAI API that makes it easy to perform natural language and code tasks like semantic search, clustering, topic modeling, and classification.', 14, 'OpenAI Blog', 'https://openai.com/index/introducing-text-and-code-embeddings', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Product"]', '2022-01-25 08:00:00.000000', '2026-03-16 06:51:03.541144', 'https://openai.com/index/introducing-text-and-code-embeddings', 0.0, 0);
