INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (927, 'WebGPT: Improving the factual accuracy of language models through web browsing', 'We’ve fine-tuned GPT-3 to more accurately answer open-ended questions using a text-based web browser.', 'We’ve fine-tuned GPT-3 to more accurately answer open-ended questions using a text-based web browser.', 14, 'OpenAI Blog', 'https://openai.com/index/webgpt', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2021-12-16 08:00:00.000000', '2026-03-16 06:51:03.541164', 'https://openai.com/index/webgpt', 0.0, 0);
